def test_export_json_helpers_round_trip():
    payload = png_bytes(solid_raster(4, 4, 1, 2, 3))
    analyze_text = export_analyze_json(payload, "tiny.png")
    validate_text = export_validate_json(payload, "tiny.png")
    compare_text = export_compare_json(payload, "a.png", payload, "b.png")
    for text in (analyze_text, validate_text, compare_text):
        parsed = json.loads(text)
        assert isinstance(parsed, dict)
        assert parsed["type"] in {"analyze", "validate", "compare"}
